import React, { useEffect, useMemo, useRef, useState } from 'react';
import * as adminServiceModule from '../../services/adminService';
import { useAuth } from '../../context/AuthContext';

const adminService = (adminServiceModule as any).default || adminServiceModule;

const CUSTOMERS_CACHE_KEY = 'admin_users_cache_v2';
const AUTO_REFRESH_MS = 15000;

const readCachedCustomers = () => {
    try {
        const raw = localStorage.getItem(CUSTOMERS_CACHE_KEY);
        if (!raw) {
            return { users: [], orders: [], stats: null };
        }

        const parsed = JSON.parse(raw);
        return {
            users: Array.isArray(parsed.users) ? parsed.users : [],
            orders: Array.isArray(parsed.orders) ? parsed.orders : [],
            stats: parsed.stats && typeof parsed.stats === 'object' ? parsed.stats : null,
        };
    } catch {
        return { users: [], orders: [], stats: null };
    }
};

export default function AdminUsers() {
    const { user: currentUser } = useAuth();
    const cachedData = readCachedCustomers();
    const [users, setUsers] = useState(cachedData.users);
    const [orders, setOrders] = useState(cachedData.orders);
    const [stats, setStats] = useState(cachedData.stats);
    const [usersLoadIssue, setUsersLoadIssue] = useState('');
    const [hydrating, setHydrating] = useState(!cachedData.users.length && !cachedData.stats);
    const [query, setQuery] = useState('');
    const [statusFilter, setStatusFilter] = useState('all');
    const [viewingUser, setViewingUser] = useState<any>(null);
    const hasSyncedRef = useRef(false);

    useEffect(() => {
        const hydrateNow = async () => {
            await loadCustomers({ includeOrders: false });
            window.setTimeout(() => {
                loadCustomers({ silent: true, includeOrders: true });
            }, 0);
        };

        hydrateNow();

        const intervalId = window.setInterval(() => {
            loadCustomers({ silent: true, includeOrders: true });
        }, AUTO_REFRESH_MS);

        const handleVisibility = () => {
            if (document.visibilityState === 'visible') {
                loadCustomers({ silent: true, includeOrders: true });
            }
        };

        document.addEventListener('visibilitychange', handleVisibility);

        return () => {
            window.clearInterval(intervalId);
            document.removeEventListener('visibilitychange', handleVisibility);
        };
    }, []);

    useEffect(() => {
        if (!hasSyncedRef.current) {
            return;
        }

        localStorage.setItem(CUSTOMERS_CACHE_KEY, JSON.stringify({
            users,
            orders,
            stats,
        }));
    }, [orders, stats, users]);

    const loadCustomers = async ({ silent = false, includeOrders = true } = {}) => {
        try {
            const requests = [adminService.getUsers(), adminService.getStats()];
            if (includeOrders) {
                requests.splice(1, 0, adminService.getAllOrders({
                    timeout: 30000,
                    params: {
                        page: 1,
                        per_page: 300,
                        include_items: false,
                        include_users: false,
                    },
                }));
            }

            const results = await Promise.allSettled(requests);
            const usersResult = results[0];
            const ordersResult = includeOrders ? results[1] : null;
            const statsResult = includeOrders ? results[2] : results[1];

            if (usersResult.status === 'fulfilled') {
                const usersResponse = usersResult.value;
                setUsers(usersResponse.data.data.data || usersResponse.data.data || []);
                setUsersLoadIssue('');
            } else if (!silent) {
                if ((cachedData.users || []).length === 0) {
                    setUsersLoadIssue('User data could not be loaded right now. Please refresh or check server connection.');
                }
            }

            if (includeOrders && ordersResult?.status === 'fulfilled') {
                const ordersResponse = ordersResult.value;
                setOrders(ordersResponse.data.data.data || ordersResponse.data.data || []);
            }

            if (statsResult.status === 'fulfilled') {
                const statsResponse = statsResult.value;
                setStats(statsResponse.data.data || null);
            }
        } catch (err) {
            console.error('Failed to load customers data:', err);
            if (!silent && (cachedData.users || []).length === 0 && (cachedData.orders || []).length === 0 && !cachedData.stats) {
                setUsersLoadIssue('User data could not be loaded right now. Please refresh or check server connection.');
            }
        } finally {
            setHydrating(false);
            hasSyncedRef.current = true;
        }
    };

    const formatDate = (dateValue) => {
        if (!dateValue) {
            return '-';
        }

        const date = new Date(dateValue);
        return Number.isNaN(date.getTime()) ? '-' : date.toLocaleString();
    };

    const visibleUsers = useMemo(() => {
        return users.filter((user) => String(user.role || '').toLowerCase() !== 'admin');
    }, [users]);

    const resolveOrderOwnerKey = (order) => {
        const idKey = String(order?.user_id || '').trim();
        if (idKey) {
            return { key: idKey, type: 'id' };
        }

        const emailKey = String(order?.user?.email || '').trim().toLowerCase();
        if (emailKey) {
            return { key: emailKey, type: 'email' };
        }

        return { key: '', type: 'none' };
    };

    const userRows = useMemo(() => {
        const orderTotalsByUser = orders.reduce((accumulator, order) => {
            const owner = resolveOrderOwnerKey(order);
            if (!owner.key) {
                return accumulator;
            }

            if (!accumulator[owner.key]) {
                accumulator[owner.key] = { orders: 0, spent: 0 };
            }

            accumulator[owner.key].orders += 1;
            accumulator[owner.key].spent += Number(order.total_amount || 0);
            return accumulator;
        }, {});

        const search = query.trim().toLowerCase();

        return visibleUsers
            .map((user) => {
                const idKey = String(user.id || '').trim();
                const emailKey = String(user.email || '').trim().toLowerCase();
                const statsById = idKey ? orderTotalsByUser[idKey] : null;
                const statsByEmail = emailKey ? orderTotalsByUser[emailKey] : null;
                const customerStats = statsById || statsByEmail || { orders: 0, spent: 0 };

                return {
                    ...user,
                    order_count: customerStats.orders,
                    total_spent: customerStats.spent,
                };
            })
            .filter((user) => {
                const matchesStatus = statusFilter === 'all' || (statusFilter === 'active' ? user.is_active : !user.is_active);
                const haystack = [user.name, user.email, user.phone]
                    .filter(Boolean)
                    .join(' ')
                    .toLowerCase();

                return matchesStatus && (!search || haystack.includes(search));
            });
    }, [orders, query, statusFilter, visibleUsers]);

    const summaryCards = useMemo(() => {
        const activeUsers = visibleUsers.filter((user) => user.is_active).length;
        const totalRevenue = Number(stats?.total_revenue || 0);
        const totalOrders = Number(stats?.total_orders || 0);
        const avgOrderValue = totalOrders > 0 ? totalRevenue / totalOrders : 0;

        return [
            { label: 'Total Users', value: visibleUsers.length, icon: '✉', accent: 'blue' },
            { label: 'Active Users', value: activeUsers, icon: '✓', accent: 'green' },
            { label: 'Total Revenue', value: `₱${totalRevenue.toFixed(0)}`, icon: '$', accent: 'purple' },
            { label: 'Avg Order Value', value: `₱${avgOrderValue.toFixed(0)}`, icon: '$', accent: 'orange' },
        ];
    }, [stats, visibleUsers]);

    const totalUsers = useMemo(() => visibleUsers.length, [visibleUsers]);

    const viewedUserOrders = useMemo(() => {
        if (!viewingUser?.id) {
            return [];
        }

        const viewId = String(viewingUser.id || '').trim();
        const viewEmail = String(viewingUser.email || '').trim().toLowerCase();

        return orders
            .filter((order) => {
                const owner = resolveOrderOwnerKey(order);
                if (!owner.key) {
                    return false;
                }

                if (owner.type === 'id') {
                    return owner.key === viewId || (viewEmail && String(order?.user?.email || '').trim().toLowerCase() === viewEmail);
                }

                return viewEmail && owner.key === viewEmail;
            })
            .sort((a, b) => new Date(b.created_at || 0).getTime() - new Date(a.created_at || 0).getTime());
    }, [orders, viewingUser]);

    const toggleUserStatus = async (targetUser) => {
        const userId = targetUser?.id;
        if (!userId) {
            return;
        }

        setUsersLoadIssue('');
        const previousActive = Boolean(targetUser?.is_active);

        // Optimistic UI update for instant action feedback.
        setUsers((prevUsers) => prevUsers.map((item) => (
            String(item.id) === String(userId)
                ? { ...item, is_active: !previousActive }
                : item
        )));

        try {
            const response = await adminService.toggleUserStatus(userId);
            const updatedUser = response?.data?.data || null;

            if (updatedUser) {
                setUsers((prevUsers) => prevUsers.map((item) => (
                    String(item.id) === String(userId)
                        ? { ...item, ...updatedUser }
                        : item
                )));
            }
        } catch (error) {
            console.error('Failed to toggle user status:', error);
            setUsers((prevUsers) => prevUsers.map((item) => (
                String(item.id) === String(userId)
                    ? { ...item, is_active: previousActive }
                    : item
            )));
            setUsersLoadIssue(error?.response?.data?.message || 'Unable to update user status right now.');
        }
    };

    const deleteUser = async (targetUser) => {
        const email = String(targetUser?.email || '').trim();
        if (!email) {
            return;
        }

        if (!window.confirm(`Delete ${targetUser.name || email}? This will remove the user from the system and the admin list.`)) {
            return;
        }

        const userId = targetUser?.id;
        const snapshotUser = { ...targetUser };
        setUsersLoadIssue('');
        setUsers((prevUsers) => prevUsers.filter((item) => String(item.email || '') !== email));

        try {
            await adminService.deleteUser({
                email,
                auth_user_id: targetUser?.auth_user_id || '',
            });
        } catch (error) {
            console.error('Failed to delete user:', error);
            setUsers((prevUsers) => {
                const alreadyExists = prevUsers.some((item) => String(item.email || '') === email);
                return alreadyExists ? prevUsers : [...prevUsers, snapshotUser];
            });
            setUsersLoadIssue(error?.response?.data?.message || 'Unable to delete user right now.');
        }
    };

    return (
        <div className="admin-page-content admin-customers-page">
            <div className="customers-header-row">
                <div>
                    <h2>User Management</h2>
                    <p>Manage your user database</p>
                </div>

                <div className="customers-page-badge">Users</div>
            </div>

            {hydrating && !usersLoadIssue && (
                <div className="admin-page-inline-status">Loading user data in the background...</div>
            )}

            <section className="customer-summary-grid">
                {summaryCards.map((card) => (
                    <article className={`customer-summary-card customer-summary-card--${card.accent}`} key={card.label}>
                        <span className="customer-summary-icon">{card.icon}</span>
                        <div>
                            <p>{card.label}</p>
                            <strong>{card.value}</strong>
                        </div>
                    </article>
                ))}
            </section>

            <div className="customers-panel">
                <div className="customers-toolbar">
                    <div className="customers-search">
                        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" aria-hidden="true">
                            <circle cx="11" cy="11" r="7" />
                            <path d="m20 20-3.5-3.5" />
                        </svg>
                        <input
                            type="text"
                            placeholder="Search by name, email, or phone..."
                            value={query}
                            onChange={(e) => setQuery(e.target.value)}
                        />
                    </div>

                    <div className="customers-filter">
                        <select value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)}>
                            <option value="all">All Status</option>
                            <option value="active">Active</option>
                            <option value="inactive">Inactive</option>
                        </select>
                    </div>
                </div>

                <div className="customers-table">
                <table>
                    <thead>
                        <tr>
                            <th>User</th>
                            <th>Contact</th>
                            <th>Orders</th>
                            <th>Total Spent</th>
                            <th>Join Date</th>
                            <th>Role</th>
                            <th>Status</th>
                            <th>Action</th>
                        </tr>
                    </thead>
                    <tbody>
                        {userRows.length > 0 ? userRows.map((customer) => (
                            <tr key={customer.id}>
                                <td>
                                    <div className="customer-name-cell">
                                        <span className="customer-avatar-mini" aria-hidden="true">
                                            {customer.avatar_url ? (
                                                <img src={customer.avatar_url} alt="" />
                                            ) : (
                                                (customer.name || 'U').charAt(0).toUpperCase()
                                            )}
                                        </span>
                                        <div>
                                            <strong>{customer.name || '-'}</strong>
                                            <span>CUST-{String(customer.id).padStart(3, '0')}</span>
                                        </div>
                                    </div>
                                </td>
                                <td>
                                    <div className="customer-contact-cell">
                                        <span>{customer.email || '-'}</span>
                                        <span>{customer.phone || '-'}</span>
                                    </div>
                                </td>
                                <td className="numeric-cell">{customer.order_count || 0}</td>
                                <td className="numeric-cell">₱{Number(customer.total_spent || 0).toFixed(2)}</td>
                                <td>{customer.created_at ? new Date(customer.created_at).toLocaleDateString() : '-'}</td>
                                <td>
                                    <span className={`customer-role-badge customer-role-badge--${customer.role || 'customer'}`}>
                                        {customer.role || 'customer'}
                                    </span>
                                </td>
                                <td>
                                    <span className={`customer-status customer-status--${customer.is_active ? 'active' : 'inactive'}`}>
                                        {customer.is_active ? 'Active' : 'Inactive'}
                                    </span>
                                </td>
                                <td>
                                    <div className="users-action-group">
                                        <button
                                            type="button"
                                            className="users-action-btn users-action-btn--view"
                                            onClick={() => setViewingUser(customer)}
                                        >
                                            View
                                        </button>
                                        {String(customer.id) === String(currentUser?.id) ? (
                                            <span className="users-action-note">Current User</span>
                                        ) : (
                                            <>
                                                <button
                                                    type="button"
                                                    className={`users-action-btn ${customer.is_active ? 'users-action-btn--deactivate' : 'users-action-btn--activate'}`}
                                                    onClick={() => toggleUserStatus(customer)}
                                                >
                                                    {customer.is_active ? 'Deactivate' : 'Activate'}
                                                </button>
                                                <button
                                                    type="button"
                                                    className="users-action-btn users-action-btn--delete"
                                                    onClick={() => deleteUser(customer)}
                                                >
                                                    Delete
                                                </button>
                                            </>
                                        )}
                                    </div>
                                </td>
                            </tr>
                        )) : (
                            <tr>
                                <td colSpan={8} className="orders-empty-state">
                                    {usersLoadIssue || (totalUsers === 0 ? 'No user accounts found yet.' : 'No users match the current search/filter.')}
                                </td>
                            </tr>
                        )}
                    </tbody>
                </table>
                </div>
            </div>

            {viewingUser && (
                <div className="users-view-modal" role="dialog" aria-modal="true" aria-labelledby="users-view-title">
                    <div className="users-view-modal__backdrop" onClick={() => setViewingUser(null)} />
                    <div className="users-view-modal__panel">
                        <div className="users-view-modal__head">
                            <div>
                                <h3 id="users-view-title">Customer Details</h3>
                                <p>{viewingUser.name || '-'}</p>
                            </div>
                            <button type="button" className="users-view-modal__close" onClick={() => setViewingUser(null)}>
                                ×
                            </button>
                        </div>

                        <div className="users-view-modal__grid">
                            <div>
                                <span>Avatar</span>
                                <strong>{viewingUser.avatar_url ? 'Available' : 'Not set'}</strong>
                            </div>
                            <div>
                                <span>Email</span>
                                <strong>{viewingUser.email || '-'}</strong>
                            </div>
                            <div>
                                <span>Phone</span>
                                <strong>{viewingUser.phone || '-'}</strong>
                            </div>
                            <div>
                                <span>Address</span>
                                <strong>{viewingUser.address || '-'}</strong>
                            </div>
                            <div>
                                <span>Billing Address</span>
                                <strong>{viewingUser.billing_address || viewingUser.address || '-'}</strong>
                            </div>
                            <div>
                                <span>Shipping Address</span>
                                <strong>{viewingUser.shipping_address || viewingUser.address || '-'}</strong>
                            </div>
                            <div>
                                <span>City</span>
                                <strong>{viewingUser.city || '-'}</strong>
                            </div>
                            <div>
                                <span>Postal Code</span>
                                <strong>{viewingUser.postal_code || '-'}</strong>
                            </div>
                            <div>
                                <span>Status</span>
                                <strong>{viewingUser.is_active ? 'Active' : 'Inactive'}</strong>
                            </div>
                            <div>
                                <span>Role</span>
                                <strong>{viewingUser.role || 'customer'}</strong>
                            </div>
                            <div>
                                <span>Joined</span>
                                <strong>{formatDate(viewingUser.created_at)}</strong>
                            </div>
                        </div>

                        <div className="users-view-modal__orders">
                            <h4>Customer Orders ({viewedUserOrders.length})</h4>
                            {viewedUserOrders.length === 0 ? (
                                <p className="users-view-modal__empty">No orders yet.</p>
                            ) : (
                                <div className="users-view-modal__orders-table-wrap">
                                    <table className="users-view-modal__orders-table">
                                        <thead>
                                            <tr>
                                                <th>Order #</th>
                                                <th>Date</th>
                                                <th>Status</th>
                                                <th>Total</th>
                                            </tr>
                                        </thead>
                                        <tbody>
                                            {viewedUserOrders.map((order) => (
                                                <tr key={order.id}>
                                                    <td>{order.order_number || `ORD-${order.id}`}</td>
                                                    <td>{formatDate(order.created_at)}</td>
                                                    <td>{order.status || 'processing'}</td>
                                                    <td>₱{Number(order.total_amount || 0).toFixed(2)}</td>
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                            )}
                        </div>

                        <div className="users-view-modal__actions">
                            <button type="button" className="users-action-btn users-action-btn--view" onClick={() => setViewingUser(null)}>
                                Close
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}
